  "sentences": [
    {
      "text": "今天天氣很熱，我心情不好。",
      "pinyin": "Jīntiān tiānqì hěn rè, wǒ xīnqíng bù hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 re4, wo3 xin1qing2 bu4 hao3.",
      "translation_en": "The weather is very hot today, and I'm in a bad mood.",
      "translation_ko": "오늘 날씨가 매우 더워서 기분이 안 좋아요."
    },
    {
      "text": "下雨天很涼快，我的心情很舒服。",
      "pinyin": "Xiàyǔ tiān hěn liángkuài, wǒ de xīnqíng hěn shūfú.",
      "pinyin_numeric": "xia4yu3 tian1 hen3 liang2kuai4, wo3 de xin1qing2 hen3 shu1fu2.",
      "pinyin_numeric": "xia4yu3 tian1 hen3 liang2kuai4, wo3 de xin1qing2 hen3 shu1fu2.",
      "translation_en": "Rainy days are cool, and I feel very comfortable.",
      "translation_ko": "비 오는 날은 시원해서 기분이 아주 편안해요."
    },
    {
      "text": "颱風天風很大，我很緊張。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ hěn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 hen3 jin3zhang1.",
      "translation_en": "On typhoon days the wind is very strong, and I'm very nervous.",
      "translation_ko": "태풍이 오는 날은 바람이 매우 세서 긴장돼요."
    },
    {
      "text": "晴天太陽很大，可是我很開心。",
      "pinyin": "Qíngtiān tàiyáng hěn dà, kěshì wǒ hěn kāixīn.",
      "pinyin_numeric": "qing2tian1 tai4yang2 hen3 da4, ke3shi4 wo3 hen3 kai1xin1.",
      "translation_en": "On sunny days the sun is very strong, but I'm very happy.",
      "translation_ko": "맑은 날은 태양이 매우 강하지만 저는 아주 기뻐요."
    },
    {
      "text": "今天溫度三十度，天氣很悶熱。",
      "pinyin": "Jīntiān wēndù sānshí dù, tiānqì hěn mēnrè.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, tian1qi4 hen3 men1re4.",
      "translation_en": "Today the temperature is 30 degrees, and the weather is very muggy.",
      "translation_ko": "오늘 기온이 30도라서 날씨가 매우 후덥지근해요."
    },
    {
      "text": "陰天很舒服，我的心情也很好。",
      "pinyin": "Yīntiān hěn shūfú, wǒ de xīnqíng yě hěn hǎo.",
      "pinyin_numeric": "yin1tian1 hen3 shu1fu2, wo3 de xin1qing2 ye3 hen3 hao3.",
      "translation_en": "Cloudy days are very comfortable, and my mood is also very good.",
      "translation_ko": "흐린 날은 아주 쾌적하고 제 기분도 좋아요."
    },
    {
      "text": "下雨天路很滑，要小心走路。",
      "pinyin": "Xiàyǔ tiān lù hěn huá, yào xiǎoxīn zǒulù.",
      "pinyin_numeric": "xia4yu3 tian1 lu4 hen3 hua2, yao4 xiao3xin1 zou3lu4.",
      "translation_en": "On rainy days the road is very slippery; you need to walk carefully.",
      "translation_ko": "비 오는 날은 길이 미끄러우니 조심해서 걸어야 해요."
    },
    {
      "text": "今天天氣很冷，我沒有精神。",
      "pinyin": "Jīntiān tiānqì hěn lěng, wǒ méiyǒu jīngshén.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 leng3, wo3 mei2you3 jing1shen2.",
      "translation_en": "The weather is very cold today, and I have no energy.",
      "translation_ko": "오늘 날씨가 매우 추워서 기운이 없어요."
    },
    {
      "text": "晴天很熱鬧，我的心情很開心。",
      "pinyin": "Qíngtiān hěn rènào, wǒ de xīnqíng hěn kāixīn.",
      "pinyin_numeric": "qing2tian1 hen3 re4nao4, wo3 de xin1qing2 hen3 kai1xin1.",
      "translation_en": "Sunny days are very lively, and my mood is very happy.",
      "translation_ko": "맑은 날은 매우 활기차서 제 기분이 아주 즐거워요."
    },
    {
      "text": "颱風天風很大，我很擔心。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ hěn dānxīn.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 hen3 dan1xin1.",
      "translation_en": "On typhoon days the wind is very strong, and I'm very worried.",
      "translation_ko": "태풍이 오는 날은 바람이 매우 세서 걱정이 돼요."
    }
  ]
}
